DO $$
DECLARE
    result jsonb;
    condition text;
    score float8;
    left_rows jsonb := '[
      {"customer_id":"c1","email":"a@example.com","amount":42},
      {"customer_id":"c2","email":"b@example.com","amount":64},
      {"customer_id":"c3","email":"c@example.com","amount":13}
    ]'::jsonb;
    right_rows jsonb := '[
      {"customer_id":"c1","region":"west"},
      {"customer_id":"c2","region":"east"},
      {"customer_id":"c4","region":"north"}
    ]'::jsonb;
    started timestamptz := clock_timestamp();
BEGIN
    LOOP
        SELECT rvbbit.suggest_join_keys(left_rows, right_rows) INTO result;
        EXIT WHEN result IS NOT NULL;
        IF clock_timestamp() - started > interval '2 minutes' THEN
            RAISE EXCEPTION 'suggest_join_keys returned NULL after readiness window';
        END IF;
        PERFORM pg_sleep(2);
    END LOOP;

    IF jsonb_typeof(result->'candidates') <> 'array'
       OR jsonb_array_length(result->'candidates') = 0 THEN
        RAISE EXCEPTION 'unexpected join candidate shape: %', result;
    END IF;

    SELECT rvbbit.best_join_condition(left_rows, right_rows) INTO condition;
    IF condition IS NULL OR position('customer_id' in condition) = 0 THEN
        RAISE EXCEPTION 'unexpected best join condition: %', condition;
    END IF;

    SELECT rvbbit.join_key_confidence('["c1","c2","c3"]'::jsonb, '["c1","c2","c4"]'::jsonb) INTO score;
    IF score < 0.5 THEN
        RAISE EXCEPTION 'expected useful join confidence, got %', score;
    END IF;
END
$$;

DO $$
DECLARE
    result jsonb;
    label text;
    started timestamptz := clock_timestamp();
BEGIN
    LOOP
        SELECT rvbbit.classify_zero_shot_base(
            'customer cannot log in after the MFA reset',
            'auth,billing,shipping,fraud'
        ) INTO result;
        EXIT WHEN result IS NOT NULL;
        IF clock_timestamp() - started > interval '2 minutes' THEN
            RAISE EXCEPTION 'classify_zero_shot_base returned NULL after readiness window';
        END IF;
        PERFORM pg_sleep(2);
    END LOOP;

    IF jsonb_typeof(result) <> 'object'
       OR NOT (result ? 'label')
       OR NOT (result ? 'score')
       OR NOT (result ? 'scores') THEN
        RAISE EXCEPTION 'unexpected zero-shot result shape: %', result;
    END IF;
    IF NOT (result->>'label' = ANY (ARRAY['auth','billing','shipping','fraud'])) THEN
        RAISE EXCEPTION 'zero-shot label was outside candidate set: %', result;
    END IF;

    SELECT rvbbit.classify(
        'customer cannot log in after the MFA reset',
        'auth,billing,shipping,fraud'
    ) INTO label;
    IF NOT (label = ANY (ARRAY['auth','billing','shipping','fraud'])) THEN
        RAISE EXCEPTION 'bundled classify label was outside candidate set: %', label;
    END IF;

    SELECT rvbbit.classify_row_zero_shot_base(
        '{"ticket":"customer cannot log in after the MFA reset","plan":"enterprise"}'::jsonb,
        'auth,billing,shipping,fraud'
    ) INTO result;
    IF jsonb_typeof(result) <> 'object'
       OR NOT (result ? 'label')
       OR NOT (result ? 'score')
       OR NOT (result ? 'scores') THEN
        RAISE EXCEPTION 'unexpected row zero-shot result shape: %', result;
    END IF;
    IF NOT (result->>'label' = ANY (ARRAY['auth','billing','shipping','fraud'])) THEN
        RAISE EXCEPTION 'row zero-shot label was outside candidate set: %', result;
    END IF;

    SELECT rvbbit.semantic_classify(
        'customer cannot log in after the MFA reset',
        'auth,billing,shipping,fraud'
    ) INTO label;
    IF NOT (label = ANY (ARRAY['auth','billing','shipping','fraud'])) THEN
        RAISE EXCEPTION 'bundled semantic_classify label was outside candidate set: %', label;
    END IF;

    SELECT rvbbit.bucket(
        'customer cannot log in after the MFA reset',
        'auth,billing,shipping,fraud'
    ) INTO label;
    IF NOT (label = ANY (ARRAY['auth','billing','shipping','fraud'])) THEN
        RAISE EXCEPTION 'bundled bucket label was outside candidate set: %', label;
    END IF;

    SELECT rvbbit.intent('customer cannot log in after the MFA reset') INTO label;
    IF coalesce(btrim(label), '') = '' THEN
        RAISE EXCEPTION 'bundled intent operator returned empty label';
    END IF;
END
$$;

