DO $$
DECLARE
    missing text[];
    probe jsonb;
BEGIN
    SELECT array_agg(expected.name ORDER BY expected.name)
    INTO missing
    FROM (VALUES
        ('hindsight_memory_status'),
        ('hindsight_memory_retain'),
        ('hindsight_memory_recall'),
        ('hindsight_memory_reflect')
    ) AS expected(name)
    WHERE NOT EXISTS (
        SELECT 1
        FROM rvbbit.operators op
        WHERE op.name = expected.name
          AND op.cache_policy = 'never'
    );

    IF missing IS NOT NULL THEN
        RAISE EXCEPTION 'missing Hindsight memory operators: %', missing;
    END IF;

    SELECT rvbbit.hindsight_memory_status('hindsight_default') INTO probe;
    IF probe IS NULL THEN
        RAISE EXCEPTION 'rvbbit.hindsight_memory_status returned NULL';
    END IF;

    -- Non-idempotent and user-data-bearing wrappers are validated by catalog
    -- presence here; exercising them would mutate an acceptance-test bank.
    IF false THEN
        PERFORM rvbbit.hindsight_memory_retain('__acceptance__', 'noop', '{}'::jsonb, 'hindsight_default', true);
        PERFORM rvbbit.hindsight_memory_recall('__acceptance__', 'noop', '{}'::jsonb, 'hindsight_default');
